shold\"},null]},{\"!=\":[{\"var\":\"rule_params.values.single_txn_amt_gteq_threshold\
"},null]},{\"!=\":[{\"var\":\"rule_params.values.count_threshold\"},null]}]},{\"if\":
[{\"and\":[{\"!=\":[{\"var\":\"txn.attribs.card_country_code\"},null]},{\"!=\":[{\"va
r\":\"txn.attribs.card_country_code\"},\"\"]},{\"!=\":[{\"var\":\"txn.attribs.card_co
untry_code\"},\"IN\"]},{\">=\":[{\"var\":\"observations.instructed_amount\"},{\"*\":[
{\"var\":\"rule_params.values.single_txn_amt_gteq_threshold\"},100]}]},{\"<=\":[{\"va
