dentity_details2": "RPMMH1234K", "registered_mobile": "9821034567", "address_geolocation": "19.2183,72.9781"}, "merchant": true, "verified": true, "accountId": 55008, "itenantid": 17, "externalId": "RaviRetailBiz01", "accountName": "Ravi Prakash Mehta", "accountType": 1, "default_mcc": 5311, "expiry_date": null, "accountNumber": "504501334789", "record_status": 0, "accountProvider": "HDFC Bank", "onboarding_date": "2022-05-01T10:00:00.000"}','This case warrants further review. The account belonging to Ravi Mehta, a proprietary retail business owner in Mumbai, shows a 150% surge in monthly transaction value—from an average of ₹2,00,000 to ₹5,00,000 in March. While the business has a stable and consistent three-year history with full KYC and moderate turnover classification, this sudden jump is atypical given the past trend. The recent bulk settlement from MetroMart Distributor suggests a possible new business relationship or seasonal demand spike.','Review',17,'7e15d02d-1438-4e54-999b-e798873b68fa');


INSERT INTO agents.sqldev(itenantid,queryid,sqldescription,sqlfielddescriptions,querytemplate,docid) VALUES (17,1701,'Fetch all customers with transactions above 10L in the past month','{"customer_id": "Customer Identifier", "total_amount": "Transaction Amount", "transaction_date": "Date of Transaction"}','SELECT customer_id, SUM(amount) as total_amount FROM transactions WHERE transaction_date >= CURRENT_DATE - INTERVAL ''30 days'' GROUP BY customer_id HAVING SUM(amount) > 1000000;','8bcc892b-e441-43cd-b3fe-9d18eb859009');
INSERT INTO agents.sqldev(itenantid,queryid,sqldescription,sqlfielddescriptions,querytemplate,docid) VALUES (17,1702,'Get daily transaction count per merchant for the past 7 days','{"txn_count": "Number of Transactions", "merchant_id": "Merchant Identifier", "transaction_date": "Date of Transaction"}','SELECT merchant_id, transaction_date, COUNT(*) as txn_count FROM transactions WHERE transaction_date >= CURRENT_DATE - INTERVAL ''7 days'' GROUP BY merchant_id, transaction_date ORDER BY transaction_date DESC;','335e8411-74b6-4738-8f92-4cc4d3a81d19');
INSERT INTO agents.sqldev(itenantid,queryid,sqldescription,sqlfielddescriptions,querytemplate,docid) VALUES (17,1703,'Fetch failure reasons and their count for failed transactions in the past 15 days','{"failure_count": "Number of Failed Transactions", "failure_reason": "Reason of Transaction Failure"}','SELECT failure_reason, COUNT(*) as failure_count FROM transactions WHERE status = ''FAILED'' AND transaction_date >= CURRENT_DATE - INTERVAL ''15 days'' GROUP BY failure_reason;','a4668415-64b0-408c-8e20-8055942343c3');
INSERT INTO agents.sqldev(itenantid,queryid,sqldescription,sqlfielddescriptions,querytemplate,docid) VALUES (17,1704,'Identify customers having more than 3 active loans','{"loan_count": "Number of Active Loans", "customer_id": "Customer Identifier"}','SELECT customer_id, COUNT(*) as loan_count FROM loans WHERE status = ''ACTIVE'' GROUP BY customer_id HAVING COUNT(*) > 3;','b473a12d-bec4-4598-98e9-336a4862a3e8');
INSERT INTO agents.sqldev(itenantid,queryid,sqldescription,sqlfielddescriptions,querytemplate,docid) VALUES (17,1705,'List top 10 merchants by transaction volume in the previous month','{"merchant_id": "Merchant Identifier", "total_volume": "Total Transaction Volume"}','SELECT merchant_id, SUM(amount) as total_volume FROM transactions WHERE transaction_date >= date_trunc(''month'', CURRENT_DATE - INTERVAL ''1 month'') AND transaction_date < date_trunc(''month'', CURRENT_DATE) GROUP BY merchant_id ORDER BY total_volume DESC LIMIT 10;','befb4de8-c253-419f-88e0-d074f7c5f926');
INSERT INTO agents.sqldev(itenantid,queryid,sqldescription,sqlfielddescriptions,querytemplate,docid) VALUES (17,1706,'Identify customers with more than 20 transactions in the last 10 days','{"txn_count": "Number of Transactions", "customer_id": "Customer Identifier", "transaction_date": "Date of Transaction"}','SELECT customer_id, COUNT(*) as txn_count FROM transactions WHERE transaction_date >= CURRENT_DATE - INTERVAL ''10 days'' GROUP BY customer_id HAVING COUNT(*) > 20;','2056f51b-2777-4c74-b5cf-754ff13673e5');
INSERT INTO agents.sqldev(itenantid,queryid,sqldescription,sqlfielddescriptions,querytemplate,docid) VALUES (17,1707,'Find accounts with no transactions in the past 60 days','{"account_id": "Account Identifier", "last_txn_date": "Last Transaction Date"}','SELECT account_id, MAX(transaction_date) as last_txn_date FROM transactions GROUP BY account_id HAVING MAX(transaction_date) < CURRENT_DATE - INTERVAL ''60 days'';','ee4627db-d79e-4413-bfa4-f58b3bb83764');
INSERT INTO agents.sqldev(itenantid,queryid,sqldescription,sqlfielddescriptions,querytemplate,docid) VALUES (17,1708,'Retrieve transactions flagged as suspicious in the last month','{"flag_reason": "Reason for Flag", "transaction_id": "Transaction Identifier", "transaction_date": "Date of Transaction"}','SELECT transaction_id, flag_reason, transaction_date FROM transactions WHERE is_flagged = TRUE AND transaction_date >= CURRENT_DATE - INTERVAL ''30 days'';','08fd7ebe-527f-4612-846e-57f38d7f76f8');
INSERT INTO agents.sqldev(itenantid,queryid,sqldescription,sqlfielddescriptions,querytemplate,docid) VALUES (17,1711,'Find customers with transactions in multiple cities in last month','{"city": "City Name", "customer_id": "Customer Identifier", "transaction_count": "Transaction Count"}','SELECT customer_id, city, COUNT(*) as transaction_count FROM transactions WHERE transaction_date >= CURRENT_DATE - INTERVAL ''30 days'' GROUP BY customer_id, city HAVING COUNT(DISTINCT city) > 1;','c190010b-5ea8-487a-8cdc-8ba9d50dd674');
INSERT INTO agents.sqldev(itenantid,queryid,sqldescription,sqlfielddescriptions,querytemplate,docid) VALUES (17,1709,'List top 5 cities with the highest number of customers','{"city": "City Name", "customer_count": "Number of Customers"}','SELECT city, COUNT(*) as customer_count FROM customers GROUP BY city ORDER BY customer_count DESC LIMIT 5;','635755da-d756-484e-85e3-1887e5d35ee3');
INSERT INTO agents.sqldev(itenantid,queryid,sqldescription,sqlfielddescriptions,querytemplate,docid) VALUES (17,1710,'Get details of loan applications rejected in the last quarter','{"application_id": "Loan Application Identifier", "application_date": "Date of Application", "rejection_reason": "Reason for Rejection"}','SELECT application_id, rejection_reason, application_date FROM loan_applications WHERE status = ''REJECTED'' AND application_date >= date_trunc(''quarter'', CURRENT_DATE - INTERVAL ''1 quarter'');','1ad609a6-9b6d-4248-ba93-b5fdf9bd08bd');


INSERT INTO agents.uinavigator(id,screen_section,function,steps_to_reach,url,itenantid,docid) VALUES (1,'Party Dashboard','The party dashboard helps the user to view information in a summarized format of the data related to the payer or the payee for the last 2 days.','1. Go to https://main.msit.dronapay.net/dronaui/YBAML/user
2. Login using right credentials
3. In sidebar menu go to analytics
