INSERT INTO agents.uinavigator(id,screen_section,function,steps_to_reach,url,itenantid,docid) VALUES (2,'Transaction Profile','The transaction profile consists of all the previous and subsequent transactions with respect to the selected transaction’s account address.','1. GO to https://main.msit.dronapay.net/dronaui/YBAML/user
2. Login using right credentials
3. In sidebar menu go to analytics
4. Click Transaction Profile','https://main.msit.dronapay.net/dronaui/YBAML/user/analytics/transaction-profile-dashboard',17,'531bdb21-e127-4e7b-94e4-f4f66581de2d');
INSERT INTO agents.uinavigator(id,screen_section,function,steps_to_reach,url,itenantid,docid) VALUES (3,'Run Simulation','In this section of the Tryout tab all the previously created simulations can be run with the preset values for threshold limits or they can be altered to see if there are any changes.','1. GO to https://main.msit.dronapay.net/dronaui/YBAML/user
2. Login using right credentials
3. In sidebar menu go to case management
4. Click Case summary','https://main.msit.dronapay.net/dronaui/YBAML/user/case-management/case-summary',17,'7203a1c1-0f9b-4746-87e9-fd0854269dcd');
INSERT INTO agents.uinavigator(id,screen_section,function,steps_to_reach,url,itenantid,docid) VALUES (4,'The Transaction dashboard','The Transaction dashboard is used to filter transactions for a particular account/VPA and a date range. It shows all the transaction details (inputs, aggregations as well as evaluated response) that are associated with that particular account/vpa address for the date range selected','1. GO to https://main.msit.dronapay.net/dronaui/YBAML/user
2. Login using right credentials
3. In sidebar menu go to Analytics
4. Click Data Analyzer.
5. Select appropriate tenant.
6. Select ''Transaction'' from Dashboard drop down menu.','https://main.msit.dronapay.net/dronaui/YBAML/user/analytics/data-analyzer',17,'74ca7a17-fdfa-4373-9d35-1ea79eda5248');
INSERT INTO agents.uinavigator(id,screen_section,function,steps_to_reach,url,itenantid,docid) VALUES (5,'Account Wise Rules Triggered','This dashboard displays all the information about the rules triggered on an account-wise basis and the filters help with the in-depth extraction of information by entering date range, class, decision, and rule values.','1. GO to https://main.msit.dronapay.net/dronaui/YBAML/user
2. Login using right credentials
3. In sidebar menu go to Analytics
4. Click Data Analyzer.
5. Select appropriate tenant.
6. Select ''Accountwise Rule Triggered'' from Dashboard drop down menu.','https://main.msit.dronapay.net/dronaui/YBAML/user/analytics/data-analyzer',17,'18a003c4-b102-40a7-a69f-e2e673c9e4bb');
INSERT INTO agents.uinavigator(id,screen_section,function,steps_to_reach,url,itenantid,docid) VALUES (6,'Pendency Report','The pendency dashboard generates output for all the cases that haven’t been settled yet.  It displays all the users and the groups associated with the case along with the state of the user.','1. GO to https://main.msit.dronapay.net/dronaui/YBAML/user
2. Login using right credentials
3. In sidebar menu go to case Management
4. Click Reports
5. Select appropriate tenant.
6. Select ''Pendancy Report'' from Dashboard drop down menu.','https://main.msit.dronapay.net/dronaui/YBAML/user/case-management/reports',17,'54062c8a-ca6d-4fc7-95d2-d5b68b2c5537');
INSERT INTO agents.uinavigator(id,screen_section,function,steps_to_reach,url,itenantid,docid) VALUES (7,'Analyze simulation','Once the simulation is run the User is redirected to the Analyze simulation section. Here the user can preview the analysis of previously run simulations and the ones which were recently created.','1. GO to https://main.msit.dronapay.net/dronaui/YBAML/user
2. Login using right credentials
3. In sidebar menu go to Try Out.
4. Click ''Analyze simulation''
5. Select appropriate tenant.
6. Select right simulation name and click search','https://main.msit.dronapay.net/dronaui/YBAML/user/try-out/analyze-simulation',17,'cd2b5d79-63a7-45cd-b95b-eb36a9c9d9db');



