INSERT INTO agents.user_manual(doc_name,version,date,pageid,page_content,itenantid,docid) VALUES ('Rule Doc',5,'2025-03-24',16,'} ] }, { "dict": [ [ "status", false ], [ "score", { "var": "rule_params.error.score" } ], [ "workflow", "" ], [ "remarks", { "var": "rule_params.error.remarks" } ] ] } ] } II. Multi-Threshold Rule ● As the name suggests, multi-threshold rules have all the logical checks/conditions on the basis of multiple defined thresholds in rule params.',17,'1d47988d-303a-40c7-93a2-8e19ec078482');
INSERT INTO agents.user_manual(doc_name,version,date,pageid,page_content,itenantid,docid) VALUES ('Rule Doc',5,'2025-03-24',17,'● In multi-threshold rules, distinct fail scores and remarks are assigned to each threshold based on the requirement. For E.g., ● Sample rule logic: If {( B1 !=null & B2 != null), If {(A>B1), [True, Fail_Score_1, Workflow_Name, Fail_Remarks], If {(A>B2), [True, Fail_Score_2, Workflow_Name, Fail_Remark] [False, 0,””,””]} [False, Error Score,””,Error Remarks]} ● Sample multi-threshold rule: { "if": [ { "and": [ { "!=": [ { "var": "rule_params.values.midarray" }, null ] }, { "!=": [ { "var": "rule_params.values.acc_d01_penny_count1" }, null ] }, { "!=": [ {',17,'e08cfc89-5733-477c-948d-c8a7da7bee80');
INSERT INTO agents.user_manual(doc_name,version,date,pageid,page_content,itenantid,docid) VALUES ('Rule Doc',5,'2025-03-24',18,'"var": "rule_params.values.acc_d01_penny_count2" }, null ] }, { "!=": [ { "var": "rule_params.values.acc_d01_penny_count3" }, null ] } ] }, { "if": [ { "and": [ { "!=": [ { "var": "observations.payeeVPA.account" }, null ] }, { "<=": [ { "var": "observations.instructed_amount" }, { "*": [ { "var": "rule_params.values.penny_threshold" }, 100 ] } ] }, {',17,'226fe9d5-fb6b-4a7d-8fcc-ddee3d5bc3fa');
INSERT INTO agents.user_manual(doc_name,version,date,pageid,page_content,itenantid,docid) VALUES ('Rule Doc',5,'2025-03-24',19,'"!": { "in": [ { "var": "payer.attribs.mid" }, { "var": "rule_params.values.midarray" } ] } } ] }, { "if": [ { ">=": [ { "var": "observations.acc_penny_pt24h_txn_count" }, { "var": "rule_params.values.acc_d01_penny_count1" } ] }, { "dict": [ [ "status", true ], [ "score", { "var_array": [ { "filter": [ { "var": "rule_params.values.scoresarray" },',17,'fc967cf6-4eaa-429a-9442-6a1a1021252b');
