INSERT INTO agents.user_manual(doc_name,version,date,pageid,page_content,itenantid,docid) VALUES ('Rule Doc',5,'2025-03-24',21,'"var": "observations.acc_penny_pt24h_txn_count" }, { "var": "rule_params.values.acc_d01_penny_count2" } ] }, { "dict": [ [ "status", true ], [ "score", { "var_array": [ { "filter": [ { "var": "rule_params.values.scoresarray" }, { "==": [ { "var": "scores" } ] } ] }, 0, "scores2", "" ] } ],',17,'2c395603-1577-4b34-acb3-81a457e12bb0');
INSERT INTO agents.user_manual(doc_name,version,date,pageid,page_content,itenantid,docid) VALUES ('Rule Doc',5,'2025-03-24',22,'[ "side", { "var": "rule_params.fail.remarks" } ], [ "workflow", "Score" ], [ "remarks", { "var": "rule_params.fail.remarks" } ] ] } , { "if": [ { ">=": [ { "var": "observations.acc_penny_pt24h_txn_count" }, { "var": "rule_params.values.acc_d01_penny_count3" } ] }, { "dict": [ [ "status", true ], [',17,'6864c323-36e4-4404-8372-ce2483ec4c77');
INSERT INTO agents.user_manual(doc_name,version,date,pageid,page_content,itenantid,docid) VALUES ('Rule Doc',5,'2025-03-24',23,'"score", { "var_array": [ { "filter": [ { "var": "rule_params.values.scoresarray" }, { "==": [ { "var": "scores" } ] } ] }, 0, "scores1", "" ] } ], [ "side", { "var": "rule_params.fail.remarks" } ], [ "workflow", "Score" ], [ "remarks", { "var": "rule_params.fail.remarks" }',17,'8f2bb8ad-14de-47dc-853a-a2b5769ab04a');
INSERT INTO agents.user_manual(doc_name,version,date,pageid,page_content,itenantid,docid) VALUES ('Rule Doc',5,'2025-03-24',24,'] ] } { " d i c t " : [ [ " s t a t u s " , f a l s e ] , [ " s c o r e " , { " v a r " : " r u l e _ p a r a m s . s u c c e s s . s c o r e " } ] , [ " w o r k f l o w " , " " ] , [ " r e m a r k s " , { " v a r " : " r u l e _ p a r a m s . s u c c e s s . r e m a r k s " } ] ] } ] } , { " d i c t " : [ [ " s t a t u s " , f a l s e ] , [ " s c o r e " ,',17,'928adfa4-70da-43a7-b295-6b313781a3f1');
INSERT INTO agents.user_manual(doc_name,version,date,pageid,page_content,itenantid,docid) VALUES ('Rule Doc',5,'2025-03-24',25,'{ "var": "rule_params.error.score" } ], [ "workflow", "" ], [ "remarks", { "var": "rule_params.error.remarks" } ] ] } ] } Batch rule: Special Functions I. IN Operator ● The IN operator in JSONlogic allows you to check if a value is present in an array/variable: Syntax: { "in": [value, array] }',17,'632f87ee-7e3d-4836-8e1a-7e424a46dac5');
INSERT INTO agents.user_manual(doc_name,version,date,pageid,page_content,itenantid,docid) VALUES ('Rule Doc',5,'2025-03-24',26,'o value: The value to check if it is present in the array/variable. o array: The array/variable to search for the value Example 1: { "in": [ { "var": "payer.attribs.mid" }, { "var": "rule_params.values.midarray" } ] } In the above example, the IN operator is used to check if the value of "payer.attribs.mid" (which is a dynamic value) is present in the array rule_params.values.midarray. The array rule_params.values.midarray contains the following values: // Array "values": { "midarray": [ "IDM001", "YES0000002085960" ] } The IN operator will return true if the value of "payer.attribs.mid" is found in the rule_params.values.midarray, and false otherwise. Example 2: { "in": [ "@hdfc",',17,'913e7962-d71b-42f1-97b4-bb1e4f3b89b1');
INSERT INTO agents.user_manual(doc_name,version,date,pageid,page_content,itenantid,docid) VALUES ('Rule Doc',5,'2025-03-24',27,'{ "var": "payer.addr" } ] } In the above example, the IN operator is used to check if the value "@hdfc" is present in the value of "payer.addr" (which is a dynamic value). The IN operator will return true if the value "@hdfc" is found within the value of "payer.addr", and false otherwise. II. var_array Operator ● The var_array operator is a function in JSONlogic that allows us to fetch specific value from a dictionary key contained within an array. Syntax: var_array(data_array,array_position,key) o data_array: Refers to the array where your data is stored o array_position: Specifies the position of the dictionary within the array, from which the key-value pair is to be examined and retrieved. o key: The name of the key which needs to be fetched Example 1: { "var_array": [',17,'9a09fb53-648c-4ee4-8da3-8484794b8edc');
INSERT INTO agents.user_manual(doc_name,version,date,pageid,page_content,itenantid,docid) VALUES ('Rule Doc',5,'2025-03-24',28,'{ "var": "rule_params.values.scorearray" }, 1, "score1" ] } In the above example, the var_array function is used to fetch the value from the second index of "scorearray" i.e present in the array rule_params.values.scorearray. The array rule_params.values.scorearray contains the following: // Array "values": { "scorearray": [ { "score1": 50, "score2": 20, "score3": 10 }, { "score1": 60, "score2": 80, "score3": 90 } ]}',17,'628d343a-8eb2-43c4-9edb-4f6fd4591644');
INSERT INTO agents.user_manual(doc_name,version,date,pageid,page_content,itenantid,docid) VALUES ('Rule Doc',5,'2025-03-24',29,'Thus, the function will return a score of 60 present in second dictionary of scorearray. III. JOIN ● The JOIN function facilitates the merging of two or more data objects through a join operation based on specific requirements ● As a output, it returns an array consisting of multiple dictionaries appending the data of secondary or tertiary data object with the primary one. Syntax: { "join": [ { "var": "datalist" }, [ { "var": "observations" } ] ] }',17,'cdbce78d-b936-4cb7-894d-90035c0612bf');
INSERT INTO agents.user_manual(doc_name,version,date,pageid,page_content,itenantid,docid) VALUES ('Rule Doc',5,'2025-03-24',30,'In this instance, it will return an output appending data of observations with each dictionary item of datalist. The JOIN operation becomes valuable when you intend to carry out logical comparisons within an array, simultaneously with other data objects. IV. SOME with JOIN ● The SOME operation/function when applied in conjunction with the JOIN function, treats the merged array as a data array. ● It then proceeds to evaluate each dictionary or member within that array against a predefined set of logical checks, which are specified following the join operation. For e.g., { "if": [ { "some": [ { "join": [ { "var": "datalist" }, [ { "var": "observations"',17,'5b11e33b-93a9-4758-aa73-ca454c307b52');
INSERT INTO agents.user_manual(doc_name,version,date,pageid,page_content,itenantid,docid) VALUES ('Rule Doc',5,'2025-03-24',31,'} ] ] }, { "and": [ { "==": [ { "var": "vcfield" }, "3_pos_mcc_ticket" ] }, { "==": [ { "var": "vcvalue" }, { "cat": [ { "var": "payeeVPA.account.customer.default_mcc" } ] } ] },',17,'9bd99ffa-2118-4d67-8be2-9687d9bb2e5d');
INSERT INTO agents.user_manual(doc_name,version,date,pageid,page_content,itenantid,docid) VALUES ('Rule Doc',5,'2025-03-24',32,'{ "!=": [ { "var": "attribs.single_txn_limit" }, null ] }, { ">": [ { "var": "instructed_amount" }, { "*": [ { "var": "attribs.single_txn_limit" }, 100 ] } ] } ] } ] }, {',17,'820a9c5f-7947-4e75-8b9b-08af50920f2d');
INSERT INTO agents.user_manual(doc_name,version,date,pageid,page_content,itenantid,docid) VALUES ('Rule Doc',5,'2025-03-24',33,'"dict": [ [ "status", true ], [ "score", { "var": "rule_params.fail.score" } ], [ "workflow", "" ], [ "remarks", { "var": "rule_params.fail.remarks" } ] ] }, { "dict": [ [ "status", false',17,'a616d737-6b3b-4c40-bf80-79be1dcb54b7');
INSERT INTO agents.user_manual(doc_name,version,date,pageid,page_content,itenantid,docid) VALUES ('Rule Doc',5,'2025-03-24',34,'], [ "score", { "var": "rule_params.success.score" } ], [ "workflow", "" ], [ "remarks", { "var": "rule_params.success.remarks" } ] ] } ] } In this example, we perform a join operation between a "datalist" and "observations," the latter being a secondary data object. Consequently, the data from "observations" will be integrated with every dictionary item within the "datalist."',17,'9b1c54ac-b37f-470f-80c1-3f93340416bd');
INSERT INTO agents.user_manual(doc_name,version,date,pageid,page_content,itenantid,docid) VALUES ('Rule Doc',5,'2025-03-24',35,'Subsequently, this merged data undergoes evaluation through the "some" operation where for each dictionary within the merged dataset, a predetermined set of logical checks is applied. If these checks prove true for at least one dictionary, the result will be "True" otherwise, it will be "False" V. timeSince and days ● timeSince function returns milliseconds since given date-time. Syntax: { "timeSince": [ ]} ● days as a function converts the number of days specified to milliseconds. Useful in combination with timeSince. { "days": [ ] } ● Mostly we use timeSince in combination with the days function to calculate date-difference.',17,'605b0f75-4d4a-43ef-b3a4-826407024e9d');
INSERT INTO agents.user_manual(doc_name,version,date,pageid,page_content,itenantid,docid) VALUES ('Rule Doc',5,'2025-03-24',36,'● Note: When utilizing the timesince function, the cat function is employed solely when the variable is in date format without a timestamp. In such cases, concatenating the timestamp is necessary. However, when the timestamp is already available in the data, the concatenation is unnecessary. For e.g., Dormancy Check { ">": [ { "-": [ { "timeSince": { "cat": [ { "var": "profile.payeracc.val.lastTransactionDate.payer" }, "T23:59:59.999+05:30" ] } }, { "timeSince": { "var": "txn.ts" } } ] },',17,'8990ef22-13bb-435a-9fbf-c8b34e232a82');
INSERT INTO agents.user_manual(doc_name,version,date,pageid,page_content,itenantid,docid) VALUES ('Rule Doc',5,'2025-03-24',37,'{ "days": { "var": "rule_params.values.days1" } } ] } In this example, we are computing the time difference between the "lastTransactiondate" and the current transaction''s timestamp using timeSince function. The outcome of this calculation is expressed in milliseconds. Subsequently, we proceed to make a comparison: we assess whether the calculated number of milliseconds surpasses the "dayThreshold." In this instance, the threshold is set at 30 days, which is converted into milliseconds using the "days" function. Note: Other supported operations of JSONlogic can be viewed at https://jsonlogic.com/operations.html VI. substr Operator ● The substr operator in JSONlogic allows you to get a portion of a string. ● Give a positive start position to return everything beginning at that index. (Indexes of course start at zero.) Syntax: {"substr": ["STRING" , INDEX]}',17,'fbbafa5a-3dea-4e47-8ae9-6418c0ebb42d');
INSERT INTO agents.user_manual(doc_name,version,date,pageid,page_content,itenantid,docid) VALUES ('Rule Doc',5,'2025-03-24',38,'E x a m p l e 1 : { " a n d " : [ { " > " : [ { " c a t " : [ { " s u b s t r " : [ { " v a r " : " t x n . t s " } , 1 1 , 2 ] } , { " s u b s t r " : [ { " v a r " : " t x n . t s " } , 1 4 , 2 ] } ] } , 1 8 3 0 ] } , { " < = " : [ { " c a t " : [ { " s u b s t r " : [ {',17,'68523d05-6b2c-4643-b304-620f25d4ddec');
INSERT INTO agents.user_manual(doc_name,version,date,pageid,page_content,itenantid,docid) VALUES ('Rule Doc',5,'2025-03-24',39,'"var": "txn.ts" }, 11, 2 ] }, { "substr": [ { "var": "txn.ts" }, 14, 2 ] } ] }, 2359 ] } ] } In the provided example, the substr operator is utilized to extract the value of "txn.ts" from the 11th index, which represents a UTC Timestamp (e.g., 2024-03-21T07:00:20.503Z), and subsequently compares it with the corresponding threshold. Essentially, it checks whether the timestamp falls within the time range of 12 AM to 6 AM. VI. objectToArray Operator The objectToArray function is a custom function created to convert a nested object with its varied keys into an array',17,'e34cedb5-e9d8-459a-afd4-967c6f646684');
INSERT INTO agents.user_manual(doc_name,version,date,pageid,page_content,itenantid,docid) VALUES ('Rule Doc',5,'2025-03-24',40,'● This array can then be exposed to multiple array functions already available with JSONLogic to continue logical operations Suppose we have an object additional_mcc within Customer attribs: { “attribs” : { "additional_mcc": { "888": { "mcc": 888, "mcc_category": "Shop", "mcc_description": "Chai Shop" }, "889": { "mcc": 889, "mcc_category": "Shop", "mcc_description": "Chai Shop" }, "890": { "mcc": 890, "mcc_category": "Shop", "mcc_description": "Chai Shop" } }}',17,'5ee8ec63-d220-49ca-a944-dce203492e90');
INSERT INTO agents.user_manual(doc_name,version,date,pageid,page_content,itenantid,docid) VALUES ('Rule Doc',5,'2025-03-24',41,'Suppose you want to write a rule with a condition that payee mcc should be one of the MCCs in this object (additional_mcc). The logic then would be as follows: {"if": [ {"!!": {"var":"payee.mcc"}}, {"in": [ {"var":"payee.mcc"}, {"reduce": [ {"objectToArray": {"var": "observations.payeeVPA.account.customer.attribs.additional_mcc"}}, {"merge":[{"var":"current.mcc"}, {"var":"accumulator"}]}, []] } ]}, "payee.mcc not supplied" ]} Rationale: What we are doing here is taking out only mcc codes from the array of objects while ignoring the category and other keys.Result of the "reduce" operation will be [888, 889, 890] Since we want to perform this operation only if payee.mcc is supplied, we are wrapping this under a "truthy" ("!!") check, instead comparing it with null. Then we are using the "in" operation to look for "payee.mcc" inside that array. We are wrapping the whole "in" test within a "!" (negative) test, to get the opposite result as per the logic of the rule What do the [ ] (square brackets) after the merge operation are for?Those Empty brackets are initializers to "var: accumulator" in the "reduce" operations. if we had data like {"something": [888, 889, 890]}',17,'274e277e-6a1a-4457-8cdc-49ac4522c3fe');
INSERT INTO agents.user_manual(doc_name,version,date,pageid,page_content,itenantid,docid) VALUES ('Rule Doc',5,'2025-03-24',42,'and we wanted to sum them up; we would use following operation {"reduce":[ {"var":"something"}, {"+":[{"var":"current"}, {"var":"accumulator"}]}, 0 ]} By initializing the "reduce" operation with 0 (zero) we are telling it that our "accumulator" is a number and it is starting at zero; to perform a "+" at every item. the result will be 2667 In our case; we are using the "reduce" operation with empty brackets, indicating that our "accumulator" is an empty array. We are populating that array by using the "merge" command on every mcc code ("current.mcc") inside the array of objects. VIII. kmApart Operator This function is a custom function developed to understand distance in Kms between two strings that are comma separated with latitude and longitude information given. This function uses the Haversine function to calculate the distance Usage: { ">": [ { "kmApart": [ { "var": "txn.attribs.device.geocode" }, { "var": "observations.last_known_location" } ] }, 1 ] } Best Practices ● Rule Param Null Checks to be added in first IF: o Incorporated rule params null checks in the first IF statement for all rules. This ensures that the null checks are performed early in the process, catching any errors promptly. ● Rule Param Null Checks - Provide Error in Config Remarks: o Added error remarks in the False block for all rule params null checks. This helps in identifying and troubleshooting any issues related to the absence of rule',17,'201b5028-aee7-410c-bdbb-8c58f0dd89d4');
INSERT INTO agents.user_manual(doc_name,version,date,pageid,page_content,itenantid,docid) VALUES ('Rule Doc',5,'2025-03-24',43,'params. By providing specific error messages, it becomes easier to pinpoint the cause of the problem. ● Functional Checks and Rule Param checks should be separate: o Always separate the rule params null checks and functional checks into separate IF blocks. This improves the organization and readability of the JSON logic, making it easier to understand and maintain. ● All functional checks in one IF block: o Move all functional checks into one separate IF block. This consolidation of functional checks simplifies the logic and ensures that all the relevant checks are grouped together for better clarity and coherence. Process to Configure,Unit Test and Deploy Rules ● The process of creating rules within the FRM application can be accomplished via two methods: ● Postman API - VS Code ● Try Out - Rule Builder a) Steps to create Rules via Postman API - VS Code ● Install VS Code, ● Post-Installing click on “New Text File” and select JSON as language',17,'415f9073-3998-4f4c-a905-3c3f873ec53f');
INSERT INTO agents.user_manual(doc_name,version,date,pageid,page_content,itenantid,docid) VALUES ('Rule Doc',5,'2025-03-24',44,'● Script the rule JSON and rule params ● Unit Test the rule JSON and rule params with required data on Jupyter. Refer to Jupyter SOP. ● Once Unit tested, add the rule in Rule CSV. In the same, fill out details such as ruleID, decisionID (the decision in which you want to add the rule), vcrulename (in strings), vcruledetail(rule JSON) - in strings, vcruleparams (in strings) and vcruleorder (in string) ● To convert the required in strings use JSON-String Converter ● Once CSV is prepared, visit Postman and import the Rule CSV collection. ● Click on “Upload Rules - A” POST request and verify the Body section to ensure that all variables are properly parameterized in relation to the rule CSV. Additionally, confirm that the action parameter is explicitly set to "A" indicating addition. ● Once verified, upload rule CSV to the collection and run the collection with a delay of 500ms',17,'b02551e1-7885-45d6-9ef5-1f0caf1d9ff7');
INSERT INTO agents.user_manual(doc_name,version,date,pageid,page_content,itenantid,docid) VALUES ('Rule Doc',5,'2025-03-24',45,'● After executing the collection, check the response generated. The expected outcome should be as a response with the status "200OK" indicating that rule is added successfully ● After any additions or updates in the masters.rules file, the following actions need to be executed: ■ Execute the ui.rules script, depending on whether it involves an insertion or an update.(PFA: Generic Scripts) ■ Additionally, if additions are made, execute the sequence scripts (PFA: Sequence Scripts) b) Steps to create Rules via Try-Out Rule Builder ● Go to Drona UI, Menu -> Try Out -> Rule Builder ● Click on “Create From Scratch”',17,'7af65c04-28cc-44e4-96d5-355959d72fdd');
INSERT INTO agents.user_manual(doc_name,version,date,pageid,page_content,itenantid,docid) VALUES ('Rule Doc',5,'2025-03-24',46,'● A pop-up will appear, fill out the details such as Rule Name, Rule Description and Rule Label. It is important to note that always keep rule label as Transaction. ● Once details are filled out, click on “SUBMIT” button ● After submitting, select the parameters as per the requirement for building the rule',17,'24682afb-999f-4a2a-a4b4-7be9274f0ff8');
INSERT INTO agents.user_manual(doc_name,version,date,pageid,page_content,itenantid,docid) VALUES ('Rule Doc',5,'2025-03-24',47,'● Post-selection of parameters, click on “NEXT” button to proceed towards step 2 for building rule. ● In Step 2, you can build the rule using blockly-components or directly by scripting JSON code under “JSON View” section. ● Once built, unit Test the rule JSON with required data on Jupyter. Refer to Jupyter SOP. ● Once Unit tested, click on “NEXT” button and in step 3 define the required rule params. ● Click on “NEXT” button, once details of rule params are filled out ● As the final step, choose the dimension of the rule, and then select the option "Save to Rules Available." ● Once saved, verify the same under rules available section. ● Once verified, go to Menu -> Masters -> Rules -> Select the Decision (where you want to add the rule) ● Then from LHS panel i.e under “Transaction” section, SELECT the rule that you want to add to the decision',17,'fc1db488-1ff7-41be-af93-ebf6917665a0');
INSERT INTO agents.user_manual(doc_name,version,date,pageid,page_content,itenantid,docid) VALUES ('Rule Doc',5,'2025-03-24',48,'● After adding, click on “Send for Approval” with maker remarks ● Login with Checker credentials, select the “Approve” option and click on “Save” button. ● Here on the top right corner you have an icon to view/edit the sequence graph',17,'716e5b75-d928-4f29-a363-f4a35b887152');
INSERT INTO agents.user_manual(doc_name,version,date,pageid,page_content,itenantid,docid) VALUES ('Rule Doc',5,'2025-03-24',49,'Configuration & Storage of Rules in Database ● Eventually all the rules configured via either Postman-API or Rule UI are stored in the database in the following format under “masters.rules” table: -------------------------*********END**********-------------------- ---',17,'d388ab40-eb25-4df0-a6ea-6ca1446cd145');
INSERT INTO agents.user_manual(doc_name,version,date,pageid,page_content,itenantid,docid) VALUES ('Rule Doc',5,'2025-03-24',50,NULL,17,'0460727a-50d0-433c-9325-ccfab579c41d');
